def clean_output(self, ...):
    # ... cleaning logic ...

    if isinstance(cleaned, dict):
        with self._lock:  # Protect shared state
            self.cleansing_count += 1
            if self.config.cache_successful_patterns and cache_key:
                if len(self.success_cache) > 1000:
                    # Clear oldest 500
                    keys = list(self.success_cache.keys())[:500]
                    for k in keys:
                        del self.success_cache[k]
                self.success_cache[cache_key] = cleaned
        return cleaned

